const body = $input.first().json;

// Extraer datos de cualquier formato
let phone = '';
let content = '';
let instance = '';
let name = 'Cliente';

// Intentar extraer de diferentes formatos de Evolution API
try {
  // Formato 1: Evolution API estándar
  if (body.data && body.data.key) {
    const jid = body.data.key.remoteJid || '';
    if (jid.includes('@s.whatsapp.net')) {
      phone = jid.replace('@s.whatsapp.net', '');
    } else if (jid.includes('@')) {
      phone = jid.split('@')[0];
    }
    const msg = body.data.message || {};
    content = msg.conversation || msg.extendedTextMessage?.text || '';
    name = body.data.pushName || 'Cliente';
  }

  // Formato 2: Alternativo
  if (!phone && body.remoteJid) {
    phone = body.remoteJid.split('@')[0];
  }
  if (!phone && body.from) {
    phone = body.from.replace(/\D/g, '');
  }
  if (!content && body.body) {
    content = body.body;
  }
  if (!content && body.message) {
    content = typeof body.message === 'string' ? body.message : JSON.stringify(body.message);
  }

  // Instance
  instance = body.instance || body.instanceName || body.apikey || '';

  // Si no hay phone, usar un placeholder
  if (!phone) {
    phone = 'unknown';
  }
  if (!content) {
    content = 'mensaje';
  }
  if (!instance) {
    instance = 'default';
  }

} catch(e) {
  phone = 'error';
  content = 'error parsing: ' + e.message;
  instance = 'default';
}

return {
  phone,
  content,
  instance,
  name,
  rawEvent: body.event || 'unknown',
  timestamp: Date.now()
};

